class Solution:
    def flipMatchVoyage(self, root, voyage):
        # Independent approach: try the greedy match, then independently VERIFY by
        # applying the recorded flips to a copy of the tree and checking the
        # resulting pre-order equals voyage. If verification fails, return [-1].
        res = []
        self.idx = 0
        self.bad = False
        def walk(node):
            if node is None or self.bad:
                return
            if self.idx >= len(voyage) or node.val != voyage[self.idx]:
                self.bad = True
                return
            self.idx += 1
            if node.left and self.idx < len(voyage) and node.left.val != voyage[self.idx]:
                res.append(node.val)
                walk(node.right)
                walk(node.left)
            else:
                walk(node.left)
                walk(node.right)
        walk(root)
        if self.bad or self.idx != len(voyage):
            return [-1]
        # verify by replaying flips
        flipset = set(res)
        out = []
        def pre(node):
            if node is None:
                return
            out.append(node.val)
            if node.val in flipset:
                pre(node.right)
                pre(node.left)
            else:
                pre(node.left)
                pre(node.right)
        pre(root)
        if out != voyage:
            return [-1]
        return res

