class Solution:
    def flipMatchVoyage(self, root, voyage):
        res = []
        self.i = 0
        self.ok = True
        def dfs(node):
            if node is None or not self.ok:
                return
            if node.val != voyage[self.i]:
                self.ok = False
                return
            self.i += 1
            if node.left and self.i < len(voyage) and node.left.val != voyage[self.i]:
                res.append(node.val)
                dfs(node.right)
                dfs(node.left)
            else:
                dfs(node.left)
                dfs(node.right)
        dfs(root)
        return res if self.ok else [-1]

