var flipMatchVoyage = function(root, voyage) {
    const res = [];
    let i = 0;
    let ok = true;
    function dfs(node) {
        if (!node || !ok) return;
        if (node.val !== voyage[i]) { ok = false; return; }
        i++;
        if (node.left && i < voyage.length && node.left.val !== voyage[i]) {
            res.push(node.val);
            dfs(node.right);
            dfs(node.left);
        } else {
            dfs(node.left);
            dfs(node.right);
        }
    }
    dfs(root);
    return ok ? res : [-1];
};
